 61	    /// 获取代理IP
 62	    pub async fn get_proxy(&self, hash: &str) -> Option<IpEt> {
 63	        // Check if hash already has a proxy
 64	        {
 65	            let map = self.map.lock().await;
 66	            if let Some(ip) = map.get(hash) {
 67	                if !self.is_expires(ip.expires) {
 68	                    return Some(ip.clone());
 69	                }
 70	            }
 71	        }
 72	
 73	        // Get new proxy from pool
 74	        let ip = self.get_from_pool(hash).await?;
 75	
 76	        // Add to map
 77	        let mut map = self.map.lock().await;
 78	        map.insert(hash.to_string(), ip.clone());
 79	        Some(ip)
 80	    }
 81	
 82	    /// 从池中获取代理
 83	    async fn get_from_pool(&self, hash: &str) -> Option<IpEt> {
 84	        self.get_from_pool_inner(hash, 3).await
 85	    }
 86	
 87	    /// 从池中获取代理（内部实现，使用循环避免递归）
 88	    async fn get_from_pool_inner(&self, hash: &str, retries: u32) -> Option<IpEt> {
 89	        let mut current_retries = retries;
 90	        
 91	        while current_retries > 0 {
 92	            let ip = {
 93	                let mut pool = self.pool.lock().await;
 94	
 95	                // Find non-expired proxy that can be distributed to this hash
 96	                // 遍历池中所有IP，找到可用的
 97	                let mut idx = 0;
 98	                while idx < pool.len() {
 99	                    let ip = &pool[idx];
100	                    
101	                    // 跳过已过期的IP
102	                    if self.is_expires(ip.expires) {
103	                        pool.remove(idx);
104	                        continue;
105	                    }
106	
107	                    // 检查是否可以分配给这个hash
108	                    // 使用字符串hash以匹配C#行为
109	                    let can_distribute = !ip.distribute.contains(&hash.to_string())
110	                        && (self.max_use_count == 0 || ip.distribute.len() < self.max_use_count - 1);
111	
112	                    if can_distribute {
113	                        // 分配给这个hash
114	                        pool[idx].distribute.insert(hash.to_string());
115	                        return Some(pool[idx].clone());
116	                    }
117	                    
118	                    idx += 1;
119	                }
120	
121	                // Pool is empty or no available proxy
122	                None
123	            };
124	
125	            if ip.is_some() {
126	                return ip;
127	            }
128	
129	            // 尝试添加新代理到池
130	            current_retries -= 1;
131	            if self.add_to_pool(self.min_size).await.is_err() {
132	                // 添加失败，不再重试
133	                break;
134	            }
135	            // 添加成功，继续循环尝试获取
136	        }
137	        
138	        tracing::warn!("Proxy pool get_from_pool failed: max retries reached");
139	        None
140	    }
