142	    /// 添加代理到池
143	    async fn add_to_pool(&self, number: usize) -> Result<()> {
144	        {
145	            let mut is_request = self.is_request.lock().await;
146	            if *is_request {
147	                tracing::debug!("Proxy pool request skipped because another refill is in progress");
148	                return Ok(());
149	            }
150	            *is_request = true;
151	        }
152	
153	        let url = format!(
154	            "http://{}.user.xiecaiyun.com/api/proxies?action=getText&key={}&count={}&word=&rand=false&norepeat=true&detail=true&ltime={}&pool={}",
155	            self.proxy_user, self.api_key, number, self.live_time, self.proxy_pools
156	        );
157	
158	        match self.client.get(&url).send().await {
159	            Ok(response) => {
160	                let status = response.status();
161	                if !status.is_success() {
162	                    tracing::error!("Proxy pool request failed with status {}", status);
163	                } else if let Ok(text) = response.text().await {
164	                    let mut added = 0usize;
165	                    let mut invalid = 0usize;
166	                    let mut pool = self.pool.lock().await;
167	                    for line in text.lines() {
168	                        let parts: Vec<&str> = line.trim().split(',').collect();
169	                        if parts.len() == 5 {
170	                            if let Ok(expires) = parts[4].trim().parse::<i64>() {
171	                                if !self.is_expires(expires) {
172	                                    let addr_parts: Vec<&str> = parts[0].split(':').collect();
173	                                    if addr_parts.len() == 2 {
174	                                        if let Ok(port) = addr_parts[1].trim().parse::<u16>() {
175	                                            let ip = IpEt::new(
176	                                                addr_parts[0].trim().to_string(),
177	                                                port,
178	                                                self.proxy_user.clone(),
179	                                                self.proxy_passwd.clone(),
180	                                                expires,
181	                                            );
182	                                            pool.push(ip);
183	                                            added += 1;
184	                                        } else {
185	                                            invalid += 1;
186	                                        }
187	                                    } else {
188	                                        invalid += 1;
189	                                    }
190	                                } else {
191	                                    invalid += 1;
192	                                }
193	                            } else {
194	                                invalid += 1;
195	                            }
196	                        } else if !line.trim().is_empty() {
197	                            invalid += 1;
198	                        }
199	                    }
200	
201	                    tracing::debug!(
202	                        "Proxy pool refill result: requested={}, added={}, invalid_or_expired={}, pool_size={}",
203	                        number,
204	                        added,
205	                        invalid,
206	                        pool.len()
207	                    );
208	
209	                    if added == 0 {
210	                        let preview = text.lines().take(3).collect::<Vec<_>>().join(" | ");
211	                        tracing::warn!(
212	                            "Proxy pool returned no usable IPs. Response preview: {}",
213	                            preview
214	                        );
215	                    }
216	                } else {
217	                    tracing::error!("Failed to read proxy pool response body");
218	                }
219	            }
220	            Err(e) => {
221	                tracing::error!("Failed to get proxy list: {}", e);
222	            }
223	        }
224	
225	        {
226	            let mut is_request = self.is_request.lock().await;
227	            *is_request = false;
228	        }
229	
230	        Ok(())
231	    }
