271	    /// 获取代理URL格式
272	    pub fn get_proxy_url(&self, ip: &IpEt) -> String {
273	        if !ip.user.is_empty() && !ip.passwd.is_empty() {
274	            format!("https://{}:{}@{}:{}", ip.user, ip.passwd, ip.host, ip.port)
275	        } else {
276	            format!("https://{}:{}", ip.host, ip.port)
277	        }
278	    }
279	}
