239	    /// 启动维护任务
240	    pub fn start_maintenance(&self) {
241	        let self_clone = self.clone();
242	        tokio::spawn(async move {
243	            let mut interval = tokio::time::interval(tokio::time::Duration::from_secs(10));
244	            loop {
245	                interval.tick().await;
246	
247	                let (current_len, expired_count) = {
248	                    let mut pool = self_clone.pool.lock().await;
249	                    let before = pool.len();
250	                    pool.retain(|ip| !self_clone.is_expires(ip.expires));
251	                    let after = pool.len();
252	                    (after, before.saturating_sub(after))
253	                };
254	
255	                if current_len < self_clone.min_size {
256	                    let need = self_clone.min_size.saturating_sub(current_len);
257	                    if need > 0 {
258	                        tracing::debug!(
259	                            "Proxy pool refill requested: current={}, expired_removed={}, need={}",
260	                            current_len,
261	                            expired_count,
262	                            need
263	                        );
264	                        let _ = self_clone.add_to_pool(need).await;
265	                    }
266	                }
267	            }
268	        });
269	    }
