 87	    /// 从池中获取代理（内部实现，使用循环避免递归）
 88	    async fn get_from_pool_inner(&self, hash: &str, retries: u32) -> Option<IpEt> {
 89	        let mut current_retries = retries;
 90	        
 91	        while current_retries > 0 {
 92	            let ip = {
 93	                let mut pool = self.pool.lock().await;
 94	
 95	                // Find non-expired proxy that can be distributed to this hash
 96	                // 遍历池中所有IP，找到可用的
 97	                let mut idx = 0;
 98	                while idx < pool.len() {
 99	                    let ip = &pool[idx];
100	                    
101	                    // 跳过已过期的IP
102	                    if self.is_expires(ip.expires) {
103	                        pool.remove(idx);
104	                        continue;
105	                    }
106	
107	                    // 检查是否可以分配给这个hash
108	                    // 使用字符串hash以匹配C#行为
109	                    // 规则：同一IP最多被 max_use_count 个账户使用
110	                    let can_distribute = !ip.distribute.contains(&hash.to_string())
111	                        && (self.max_use_count == 0 || ip.distribute.len() < self.max_use_count);
112	
113	                    if can_distribute {
114	                        // 分配给这个hash
115	                        pool[idx].distribute.insert(hash.to_string());
116	                        return Some(pool[idx].clone());
117	                    }
118	                    
119	                    idx += 1;
120	                }
121	
122	                // Pool is empty or no available proxy
123	                None
124	            };
125	
126	            if ip.is_some() {
127	                return ip;
128	            }
129	
130	            // 尝试添加新代理到池
131	            current_retries -= 1;
132	            if self.add_to_pool(self.min_size).await.is_err() {
133	                // 添加失败，不再重试
134	                break;
135	            }
136	            // 添加成功，继续循环尝试获取
137	        }
138	        
139	        tracing::warn!("Proxy pool get_from_pool failed: max retries reached");
140	        None
141	    }
