   452	    async fn process_task(
   453	        task: DownloadStruct,
   454	        db: &Arc<Mutex<Database>>,
   455	        log_store: &LogState,
   456	        ocr: &Arc<Mutex<OcrSystem>>,
   457	        proxy_pool: &Option<Arc<Mutex<ProxyPool>>>,
   458	        config: &Arc<Mutex<Config>>,
   459	        sync_service: &Arc<SyncService>,
   460	        tmp_dir: &PathBuf,
   461	        _xls_dir: &PathBuf,
   462	        app_handle: &tauri::AppHandle,
   463	    ) -> anyhow::Result<()> {
   464	        let task_id = task.task_id;
   465	        let current_timestamp = || -> u32 {
   466	            std::time::SystemTime::now()
   467	                .duration_since(std::time::UNIX_EPOCH)
   468	                .unwrap_or_default()
   469	                .as_secs() as u32
   470	        };
   471	
   472	        let mut log = log_store.lock().await;
   473	        log.add(
   474	            "info".to_string(),
   475	            format!("正在处理账户 {} 的下载任务...", task.account),
   476	        );
   477	        drop(log);
   478	
   479	        let config_data = config.lock().await.clone();
   480	        let ocr_data = ocr.lock().await.clone();
   481	        let proxy_pool_data = proxy_pool.clone();
   482	
   483	        tracing::info!("[{}] Download task picked by worker", task.account);
   484	
   485	        // 代理逻辑：
   486	        // 1. enable_dynamic_proxy=true → 优先动态代理，失败则回退固定代理
   487	        // 2. enable_dynamic_proxy=false → 使用固定代理
   488	        // 3. require_proxy=true 时：无法获取任何代理则报错停止
   489	        // 4. require_proxy=false 时：无法获取代理则回退到无代理
   490	        //
   491	        // 获取固定代理 (按 task_id 或 aid 简单分配)
   492	        let fixed_proxy = if !config_data.proxy_server.is_empty() {
   493	            let idx = (task.account_id as usize) % config_data.proxy_server.len();
   494	            Some(config_data.proxy_server[idx].clone())
   495	        } else {
   496	            None
   497	        };
   498	
   499	        // 解析动态代理
   500	        let dynamic_proxy_result = if config_data.enable_dynamic_proxy {
   501	            if let Some(pool_arc) = &proxy_pool_data {
   502	                let pool = pool_arc.lock().await;
   503	                pool.get_proxy(&task.account_id.to_string()).await
   504	            } else {
   505	                None
   506	            }
   507	        } else {
   508	            None
   509	        };
   510	
   511	        // 根据配置决定最终代理
   512	        let (resolved_proxy_url, resolved_proxy_desc) = if let Some(ip) = dynamic_proxy_result {
   513	            // 动态代理获取成功
   514	            let proxy_url = if !ip.user.is_empty() && !ip.passwd.is_empty() {
   515	                format!("https://{}:{}@{}:{}", ip.user, ip.passwd, ip.host, ip.port)
   516	            } else {
   517	                format!("https://{}:{}", ip.host, ip.port)
   518	            };
   519	            (
   520	                Some(proxy_url),
   521	                Some(format!("动态代理 {}:{}", ip.host, ip.port)),
   522	            )
   523	        } else if let Some(fixed) = fixed_proxy.clone() {
   524	            // 动态代理获取失败，回退到固定代理
   525	            (
   526	                Some(fixed.clone()),
   527	                Some(format!("固定代理 {}", DownloadHandle::sanitize_proxy_desc(&fixed))),
   528	            )
   529	        } else {
   530	            // 无可用代理
   531	            if config_data.require_proxy {
   532	                // 必须使用代理，但获取不到，返回错误
   533	                tracing::error!(
   534	                    "[{}] require_proxy=true 但无法获取代理，停止下载",
   535	                    task.account
   536	                );
   537	                return Err(anyhow::anyhow!("无法获取代理IP，停止下载"));
   538	            }
   539	            (None, None)
   540	        };
   541	
   542	        let final_xls_base = config_data.get_effective_xls_dir();
   543	        let account_dir = utility::get_account_dir(&task.account);
   544	        let account_tmp_dir = tmp_dir.join(&account_dir);
   545	        let account_xls_dir = final_xls_base.join(&account_dir);
   546	
   547	        tokio::fs::create_dir_all(&account_tmp_dir).await?;
   548	        tokio::fs::create_dir_all(&account_xls_dir).await?;
   549	
   550	        // 创建下载处理器
   551	        let mut handle = DownloadHandle::new(
   552	            task.account_id,
   553	            task.account.clone(),
   554	            task.passwd.clone(),
   555	            account_tmp_dir,
   556	            account_xls_dir.clone(),
   557	            ocr_data,
   558	            proxy_pool_data,
   559	            log_store.clone(),
   560	            config_data,
   561	            db.clone(),
   562	            sync_service.clone(),
   563	            app_handle.clone(),
   564	            resolved_proxy_url,
   565	            resolved_proxy_desc,
   566	        );
   567	
   568	        tracing::info!(
   569	            "[{}] Download handle created, starting download flow",
   570	            task.account
   571	        );
   572	
   573	        // 执行下载 (Handle 内部会实时投递状态)
   574	        let task_result = handle
   575	            .download_from_last(
   576	                task.last_update,
   577	                task.replace,
   578	                task.download_type,
   579	                task.download_date.clone(),
   580	            )
   581	            .await;
   582	
   583	        tracing::info!(
   584	            "[{}] Download flow finished: success={}",
   585	            task.account,
   586	            task_result.is_ok()
   587	        );
   588	
   589	        // 对齐 C# 逻辑：
   590	        // - 成功完成时：状态始终为 1（已更新），不管是否有新数据下载
   591	        // - current: 如果有新下载用新的，否则保持原有的
   592	        // - 只有登录错误或下载失败时才设置其他状态
   593	        let (task_status, task_error, task_current) = match &task_result {
   594	            Ok(last_update_ts) => {
   595	                // 成功完成下载流程，状态为 1（已更新）
   596	                // current: 有新数据用新时间戳，无新数据保持原有 current
   597	                let current = if *last_update_ts > 0 {
   598	                    *last_update_ts
   599	                } else {
   600	                    task.current
   601	                };
   602	                (1u8, None, current)
   603	            }
   604	            Err(e) => {
   605	                let status = {
   606	                    let login_status = handle.get_login_status();
   607	                    if login_status != 0 {
   608	                        login_status
   609	                    } else {
   610	                        2
   611	                    }
   612	                };
   613	                let current = handle.get_last_success_update().max(task.current);
   614	                (status, Some(e.to_string()), current)
   615	            }
   616	        };
   617	
   618	        let now = current_timestamp();
   619	        {
   620	            let mut db_guard = db.lock().await;
   621	            db_guard.update_account_status(task.account_id, task_status, now, task_current)?;
   622	        }
   623	
   624	        let current_date = if task_current > 0 {
   625	            chrono::DateTime::<chrono::Utc>::from_timestamp(task_current as i64, 0)
   626	                .unwrap_or_default()
   627	                .format("%Y-%m-%d")
   628	                .to_string()
   629	        } else {
   630	            String::new()
   631	        };
   632	        let _ = sync_service
   633	            .sync_status_to_server(task.account_id, now, task_status, &current_date)
   634	            .await;
   635	
   636	        if let Some(id) = task_id {
   637	            let mut db_guard = db.lock().await;
   638	            if task_error.is_some() {
   639	                let _ = db_guard.update_download_task_status(
   640	                    id,
   641	                    3,
   642	                    None,
   643	                    Some(now),
   644	                    task_error.as_deref(),
   645	                );
   646	            } else {
   647	                let _ = db_guard.delete_download_tasks(&[id]);
   648	            }
   649	        }
   650	
   651	        // 归还代理IP到池中
   652	        if let Some(pool_arc) = proxy_pool {
   653	            let pool = pool_arc.lock().await;
   654	            pool.return_proxy(&task.account_id.to_string()).await;
   655	        }
   656	
   657	        task_result.map(|_| ())
   658	    }
